    vector<string> removeInvalidParentheses(string s) {
        queue<string> q;
        set<string> visited;
        bool found = false;
        q.push(s);
        visited.insert(s);
        while (!q.empty()) {
            string t = q.front();
            q.pop();
            if (isValid(t)) {
                found = true;
                if (!found2(t)) {
                    vector<string> res;
                    dfs(t, "", res);
                    return res;
                }
            }
            for (int i = 0; i < t.size(); i++) {
                if (t[i] != '(' && t[i] != ')') continue;
                string newT = t.substr(0, i) + t.substr(i + 1);
                if (visited.find(newT) == visited.end()) {
                    q.push(newT);
                    visited.insert(newT);
                }
            }
        }
        return {};
    }
    bool isValid(string s) {
        int cnt = 0;
        for (char c : s) {
            if (c == '(') cnt++;
            if (c == ')') {
                if (cnt == 0) return false;
                cnt--;
            }
        }
        return cnt == 0;
    }
    bool found2(string s) {
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '(') {
                if (i > 0 && s[i - 1] == '(') continue;
                if (i < s.size() - 1 && s[i + 1] == ')') continue;
                return false;
            }
        }
        return true;
    }
    void dfs(string s, string path, vector<string>& res) {
        if (s.empty()) res.push_back(path);
        else {
            if (s[0] == '(' || s[0] == ')') {
                dfs(s.substr(1), path, res);
                dfs(s.substr(1), path + s[0], res);
            } else {
                dfs(s.substr(1), path, res);
            }
        }
    }
};
